#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

/*
 * One-Time Pad (OTP) Implementation in C
 * 
 * OTP Requirements for Perfect Secrecy:
 * 1. Key must be truly random
 * 2. Key length >= plaintext length
 * 3. Key must be kept secret
 * 4. Key must be used only once
 */

// Generate truly random key using /dev/urandom or rand()
void generate_otp_key(unsigned char *key, size_t length) {
    FILE *urandom = fopen("/dev/urandom", "r");
    if (urandom != NULL) {
        fread(key, 1, length, urandom);
        fclose(urandom);
    } else {
        // Fallback for Windows: use rand() (NOT truly random!)
        srand(time(NULL));
        for (size_t i = 0; i < length; i++) {
            key[i] = rand() % 256;
        }
    }
}

// XOR-based OTP Encryption
// Ciphertext = Plaintext XOR Key
void otp_encrypt(const unsigned char *plaintext, 
                 const unsigned char *key, 
                 unsigned char *ciphertext, 
                 size_t length) {
    for (size_t i = 0; i < length; i++) {
        ciphertext[i] = plaintext[i] ^ key[i];
    }
}

// XOR-based OTP Decryption
// Plaintext = Ciphertext XOR Key (same operation!)
void otp_decrypt(const unsigned char *ciphertext, 
                 const unsigned char *key, 
                 unsigned char *plaintext, 
                 size_t length) {
    for (size_t i = 0; i < length; i++) {
        plaintext[i] = ciphertext[i] ^ key[i];
    }
}

// Print bytes in hexadecimal and ASCII
void print_bytes(const unsigned char *data, size_t length, const char *label) {
    printf("%s: ", label);
    for (size_t i = 0; i < length; i++) {
        printf("%02X ", data[i]);
    }
    printf("\n");

    printf("As ASCII: ");
    for (size_t i = 0; i < length; i++) {
        if (data[i] >= 32 && data[i] <= 126) {
            printf("%c", data[i]);
        } else {
            printf(".");
        }
    }
    printf("\n");
}

// Demonstrate XOR properties
void demonstrate_xor_properties() {
    printf("\n=== XOR Properties Demonstration ===\n");

    unsigned char a = 72;  // 'H'
    unsigned char b = 88;  // 'X'

    printf("Let A = 72 ('H'), B = 88 ('X')\n\n");

    // Commutative: A ^ B = B ^ A
    printf("Commutative: A^B = %d, B^A = %d -> %s\n", 
           a ^ b, b ^ a, (a ^ b) == (b ^ a) ? "EQUAL" : "NOT EQUAL");

    // Self-inverse: A ^ A = 0
    printf("Self-inverse: A^A = %d (becomes zero)\n", a ^ a);

    // Identity: A ^ 0 = A
    printf("Identity: A^0 = %d = %d\n", a ^ 0, a);

    // Used for decryption: (A ^ B) ^ B = A
    printf("Decryption: (A^B)^B = %d = %d (original)\n", (a ^ b) ^ b, a);
}

int main() {
    const char *message = "HELLO";
    size_t msg_len = strlen(message);

    unsigned char plaintext[256];
    unsigned char key[256];
    unsigned char ciphertext[256];
    unsigned char decrypted[256];

    // Copy message to buffer
    memcpy(plaintext, message, msg_len);

    printf("=== One-Time Pad Demonstration ===\n");
    printf("Message: %s\n", message);

    // Generate truly random key
    generate_otp_key(key, msg_len);
    print_bytes(key, msg_len, "Key     ");

    // Encrypt: C = P XOR K
    otp_encrypt(plaintext, key, ciphertext, msg_len);
    print_bytes(ciphertext, msg_len, "Cipher  ");

    // Decrypt: P = C XOR K
    otp_decrypt(ciphertext, key, decrypted, msg_len);
    print_bytes(decrypted, msg_len, "Decrypt ");

    printf("\nDecryption successful: %s\n", 
           (memcmp(decrypted, plaintext, msg_len) == 0) ? "YES" : "NO");

    // Demonstrate perfect secrecy
    unsigned char wrong_key[256];
    generate_otp_key(wrong_key, msg_len);
    unsigned char wrong_plaintext[256];
    otp_decrypt(ciphertext, wrong_key, wrong_plaintext, msg_len);

    printf("\nWith wrong key, we get garbage:\n");
    print_bytes(wrong_plaintext, msg_len, "Wrong   ");

    demonstrate_xor_properties();

    return 0;
}
